    ('oba',       (SELECT id FROM users WHERE email='oba@puzzle.co.jp')),
    ('tojo',      (SELECT id FROM users WHERE email='tojo@puzzle.co.jp'))
  ) AS t(key, id)
)
SELECT * FROM w; -- (確認用)

