-- ── 確認クエリ ──────────────────────────────────────────────
SELECT
  COUNT(*) FILTER (WHERE email LIKE '%@puzzle.co.jp' AND name IN ('小林','牧','黒島','大庭','東條')) AS "新担当者数",
  (SELECT COUNT(*) FROM projects WHERE id LIKE 'aa000001%') AS "新プロジェクト数",
  (SELECT COUNT(*) FROM pieces WHERE id LIKE 'bb000001%') AS "新ピース数",
  (SELECT COUNT(*) FROM connections WHERE from_piece_id LIKE 'bb000001%') AS "新接続数"
FROM users;
